import { type JSX } from 'react';

import { OverlayTooltip } from '../OverlayTooltip.js';
import { useTooltipData } from './utils.js';
import type {
  Data,
  GeometryTypes,
  HeaderData,
  TooltipValue,
} from '../types.js';

const HeaderTooltip = ({
  label,
  showRangeDuration = false,
}: {
  label?: string;
  showRangeDuration?: boolean;
}) => {
  const { data } = useTooltipData();

  return (
    <OverlayTooltip>
      <OverlayTooltip.Header
        header1={data.header1}
        subheader={data.subheader}
        label={label}
        showRangeDuration1={showRangeDuration}
      />
    </OverlayTooltip>
  );
};

const DotTooltip = <HeaderTooltip />;
const NoGeometryTooltip = <HeaderTooltip />;
const DurationTooltip = (label: string) => (
  <HeaderTooltip label={label} showRangeDuration />
);

const DualHeaderTooltip = ({
  header2,
  label,
  label2,
  duration2,
  showRangeDuration = false,
  maxLines,
}: {
  header2: HeaderData;
  label?: string;
  label2?: string;
  duration2?: string;
  showRangeDuration?: boolean;
  maxLines?: number;
}) => {
  const { data } = useTooltipData();

  return (
    <OverlayTooltip>
      <OverlayTooltip.Header
        header1={data.header1}
        header2={header2}
        subheader={data.subheader}
        label={label}
        label2={label2}
        duration2={duration2}
        showRangeDuration1={showRangeDuration}
        maxLines={maxLines}
      />
    </OverlayTooltip>
  );
};

const baseSeries = [
  {
    name: 'Series 1',
    color: '#3DD598',
    value: '100',
  },
];

type HeaderValueTuple = [TooltipValue] | [TooltipValue, TooltipValue];
type HeaderValue = TooltipValue | HeaderValueTuple;

const dateRange = (from: string, to: string): HeaderValueTuple => [
  new Date(from),
  new Date(to),
];

const DATE_RANGES = {
  secondsChanging: dateRange('2023-06-15T14:30:15', '2023-06-15T14:30:45'),
  minutesChanging: dateRange('2023-06-15T14:15:00', '2023-06-15T14:45:00'),
  hoursChanging: dateRange('2023-06-15T09:00:00', '2023-06-15T17:30:00'),
  daysChanging: dateRange('2023-06-05T10:00:00', '2023-06-25T16:30:00'),
  monthsChanging: dateRange('2023-03-15T10:00:00', '2023-09-20T14:30:00'),
  yearsChanging: dateRange('2022-12-15T10:00:00', '2024-03-20T14:30:00'),
  withSeconds: dateRange('2023-06-15T14:30:15', '2023-06-15T14:30:25'),
  crossDay: dateRange('2023-06-15T22:00:00', '2023-06-16T02:30:00'),
  sameDay: dateRange('2023-06-15T08:00:00', '2023-06-15T18:00:00'),
  fullYear: dateRange('2023-01-01T00:00:00', '2023-12-31T23:59:59'),
  janToJun: dateRange('2023-01-01', '2023-06-30'),
  janOnly: dateRange('2023-01-01', '2023-01-31'),
  fullYearSimple: dateRange('2023-01-01', '2023-12-31'),
} as const;

const createTestData = (
  geometry: GeometryTypes,
  header1: HeaderValue,
  subheader?: HeaderValue,
): (() => Data) => {
  const headerData: HeaderValueTuple = Array.isArray(header1)
    ? header1
    : [header1];
  return (): Data => ({
    geometry,
    header1: headerData,
    ...(subheader && { subheader }),
    series: baseSeries,
  });
};

